// frontend/src/components/workers/WorkerDashboard.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import { useAlert } from '../../contexts/AlertContext';
import './WorkerDashboard.css';

const WorkerDashboard = () => {
    const { user } = useAuth();
    const alert = useAlert();
    const [applications, setApplications] = useState([]);
    const [recommendedJobs, setRecommendedJobs] = useState([]);
    const [myVouchers, setMyVouchers] = useState([]);
    const [loadingVouchers, setLoadingVouchers] = useState(false);
    const [selectedVoucher, setSelectedVoucher] = useState(null);
    const [showClaimModal, setShowClaimModal] = useState(false);
    const [claimAmount, setClaimAmount] = useState(0);
    const [claimMethod, setClaimMethod] = useState('bank');
    const [stats, setStats] = useState({
        totalApplications: 0,
        pendingApplications: 0,
        acceptedApplications: 0,
        completedJobs: 0,
        totalEarnings: 0,
        voucherBalance: 0
    });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        loadDashboardData();
        loadWorkerVouchers();
    }, []);

    const loadDashboardData = async () => {
        setLoading(true);
        try {
            // Load applications
            const appsResponse = await api.get('/worker/applications');
            if (appsResponse.data.success) {
                setApplications(appsResponse.data.data);

                // Calculate stats
                const pending = appsResponse.data.data.filter(a => a.status === 'pending').length;
                const accepted = appsResponse.data.data.filter(a => a.status === 'accepted').length;
                const completed = appsResponse.data.data.filter(a => a.job_status === 'completed').length;
                const earnings = appsResponse.data.data
                    .filter(a => a.job_status === 'completed')
                    .reduce((sum, a) => sum + (a.agreed_rate || a.proposed_rate), 0);

                setStats(prev => ({
                    ...prev,
                    totalApplications: appsResponse.data.data.length,
                    pendingApplications: pending,
                    acceptedApplications: accepted,
                    completedJobs: completed,
                    totalEarnings: earnings
                }));
            }

            // Load recommended jobs
            const jobsResponse = await api.get('/jobs?status=posted');
            if (jobsResponse.data.success) {
                setRecommendedJobs(jobsResponse.data.data.slice(0, 3));
            }

        } catch (error) {
            console.error('Error loading dashboard:', error);
            setError('Failed to load dashboard data');
        } finally {
            setLoading(false);
        }
    };

    // Load worker's vouchers
    const loadWorkerVouchers = async () => {
        setLoadingVouchers(true);
        try {
            const response = await api.get('/vouchers/my');
            if (response.data.success) {
                const vouchers = response.data.data.vouchers;
                setMyVouchers(vouchers);

                // Calculate total voucher balance
                const totalBalance = vouchers
                    .filter(v => v.current_status === 'active')
                    .reduce((sum, v) => sum + v.current_balance, 0);

                setStats(prev => ({
                    ...prev,
                    voucherBalance: totalBalance
                }));
            }
        } catch (error) {
            console.error('Error loading vouchers:', error);
        } finally {
            setLoadingVouchers(false);
        }
    };

    // Handle claim voucher
    const handleClaimVoucher = (voucher) => {
        setSelectedVoucher(voucher);
        setClaimAmount(voucher.current_balance);
        setShowClaimModal(true);
    };

    // Process claim
    const handleProcessClaim = async () => {
        if (!selectedVoucher) return;

        try {
            const response = await api.post('/vouchers/claim', {
                voucher_id: selectedVoucher.id,
                amount: claimAmount,
                claim_method: claimMethod
            });

            if (response.data.success) {
                alert.success(`✅ Successfully claimed R${claimAmount}!`);
                setShowClaimModal(false);
                setSelectedVoucher(null);
                loadWorkerVouchers(); // Refresh vouchers
            }
        } catch (error) {
            console.error('Claim error:', error);
            alert.error(error.response?.data?.message || 'Failed to claim voucher');
        }
    };

    const formatDate = (dateString) => {
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
        });
    };

    const getStatusClass = (status) => {
        switch (status) {
            case 'pending': return 'status-pending';
            case 'accepted': return 'status-accepted';
            case 'rejected': return 'status-rejected';
            default: return '';
        }
    };

    const getVoucherStatusClass = (status) => {
        switch (status) {
            case 'active': return 'voucher-active';
            case 'partially_used': return 'voucher-partial';
            case 'used': return 'voucher-used';
            case 'expired': return 'voucher-expired';
            default: return '';
        }
    };

    if (loading) {
        return <div className="loading-spinner">Loading dashboard...</div>;
    }

    return (
        <div className="worker-dashboard">
            <div className="dashboard-container">
                {/* Welcome Section */}
                <div className="welcome-section">
                    <h1>Welcome back, {user?.name}! 👋</h1>
                    <p>Here's what's happening with your jobs</p>
                </div>

                {/* Stats Grid */}
                <div className="dashboard-stats">
                    <div className="stat-card">
                        <div className="stat-icon">📋</div>
                        <div className="stat-info">
                            <h3>Total Applications</h3>
                            <span className="stat-number">{stats.totalApplications}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">⏳</div>
                        <div className="stat-info">
                            <h3>Pending</h3>
                            <span className="stat-number">{stats.pendingApplications}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">✅</div>
                        <div className="stat-info">
                            <h3>Accepted</h3>
                            <span className="stat-number">{stats.acceptedApplications}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">💰</div>
                        <div className="stat-info">
                            <h3>Total Earned</h3>
                            <span className="stat-number">R {stats.totalEarnings}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">🎫</div>
                        <div className="stat-info">
                            <h3>Voucher Balance</h3>
                            <span className="stat-number">R {stats.voucherBalance}</span>
                        </div>
                    </div>
                </div>

                {error && <div className="error-message">{error}</div>}

                {/* My Vouchers Section */}
                <div className="vouchers-section">
                    <div className="section-header">
                        <h2>🎫 My Vouchers</h2>
                        <Link to="/vouchers/history" className="view-all">View History →</Link>
                    </div>

                    {loadingVouchers ? (
                        <div className="loading-spinner-small">Loading vouchers...</div>
                    ) : myVouchers.length === 0 ? (
                        <div className="empty-vouchers">
                            <p>You don't have any vouchers yet.</p>
                            <p>Vouchers will appear here when clients pay you.</p>
                        </div>
                    ) : (
                        <div className="vouchers-grid">
                            {myVouchers.map(voucher => (
                                <div key={voucher.id} className={`voucher-card ${getVoucherStatusClass(voucher.current_status)}`}>
                                    <div className="voucher-header">
                                        <span className="voucher-code">{voucher.voucher_code}</span>
                                        <span className={`voucher-status ${voucher.current_status}`}>
                                            {voucher.current_status}
                                        </span>
                                    </div>

                                    <div className="voucher-body">
                                        <div className="voucher-balance-display">
                                            <span className="balance-label">Balance:</span>
                                            <span className="balance-amount">R {voucher.current_balance}</span>
                                        </div>

                                        {voucher.template_name && (
                                            <div className="voucher-type">{voucher.template_name}</div>
                                        )}

                                        <div className="voucher-expiry">
                                            Expires: {new Date(voucher.expires_at).toLocaleDateString()}
                                        </div>
                                    </div>

                                    {voucher.current_status === 'active' && voucher.current_balance > 0 && (
                                        <div className="voucher-actions">
                                            <button 
                                                className="btn-claim"
                                                onClick={() => handleClaimVoucher(voucher)}
                                            >
                                                💰 Claim Cash
                                            </button>
                                            <Link 
                                                to={`/vouchers/use/${voucher.id}`} 
                                                className="btn-use"
                                            >
                                                Use for Jobs
                                            </Link>
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* My Applications */}
                <div className="section-header">
                    <h2>My Applications</h2>
                    <Link to="/applications" className="view-all">View All →</Link>
                </div>

                {applications.length === 0 ? (
                    <div className="empty-state">
                        <div className="empty-icon">📝</div>
                        <h3>No applications yet</h3>
                        <p>Start applying for jobs to see them here</p>
                        <Link to="/jobs" className="btn-primary">Browse Jobs</Link>
                    </div>
                ) : (
                    <div className="applications-grid">
                        {applications.slice(0, 3).map(app => (
                            <div key={app.id} className="application-card">
                                <span className={`application-status ${getStatusClass(app.status)}`}>
                                    {app.status}
                                </span>
                                <h3>{app.job_title}</h3>
                                <div className="application-details">
                                    <div className="detail-item">
                                        <span>📍</span>
                                        <span>{app.township}</span>
                                    </div>
                                    <div className="detail-item">
                                        <span>📅</span>
                                        <span>Applied {formatDate(app.created_at)}</span>
                                    </div>
                                </div>
                                <div className="application-rate">
                                    <span className="rate-label">Your quote:</span>
                                    <span className="rate-value">R {app.proposed_rate}</span>
                                </div>
                                <Link to={`/jobs/${app.job_id}`} className="btn-view">
                                    View Job
                                </Link>
                            </div>
                        ))}
                    </div>
                )}

                {/* Recommended Jobs */}
                <div className="section-header">
                    <h2>Recommended for You</h2>
                    <Link to="/jobs" className="view-all">Browse All →</Link>
                </div>

                <div className="jobs-grid">
                    {recommendedJobs.map(job => (
                        <div key={job.id} className="recommended-job">
                            <h3>{job.title}</h3>
                            <div className="job-meta">
                                <span>📍 {job.township}</span>
                                <span>⏱️ {job.estimated_hours || 'Flexible'}h</span>
                            </div>
                            <p className="job-description">
                                {job.description?.substring(0, 80)}...
                            </p>
                            <div className="job-budget">
                                Budget: R {job.budget_min} - R {job.budget_max}
                            </div>
                            <Link to={`/jobs/${job.id}`} className="btn-apply">
                                View & Apply
                            </Link>
                        </div>
                    ))}
                </div>

                {/* Quick Actions */}
                <div className="quick-actions">
                    <h2>Quick Actions</h2>
                    <div className="actions-grid">
                        <Link to={`/workers/${user?.id}`} className="action-card">
                            <span className="action-icon">👤</span>
                            <span className="action-title">Update Profile</span>
                            <span className="action-desc">Add skills, update rates</span>
                        </Link>
                        <Link to="/vouchers/my" className="action-card">
                            <span className="action-icon">🎫</span>
                            <span className="action-title">My Vouchers</span>
                            <span className="action-desc">Check balance & history</span>
                        </Link>
                        <Link to="/jobs" className="action-card">
                            <span className="action-icon">🔍</span>
                            <span className="action-title">Find Work</span>
                            <span className="action-desc">Browse available jobs</span>
                        </Link>
                        <Link to="/safety" className="action-card">
                            <span className="action-icon">🛡️</span>
                            <span className="action-title">Safety Tips</span>
                            <span className="action-desc">Stay safe while working</span>
                        </Link>
                    </div>
                </div>
            </div>

            {/* Claim Voucher Modal */}
            {showClaimModal && selectedVoucher && (
                <div className="modal-overlay" onClick={() => setShowClaimModal(false)}>
                    <div className="claim-modal" onClick={e => e.stopPropagation()}>
                        <div className="modal-header">
                            <h2>💰 Claim Voucher Cash</h2>
                            <button className="modal-close" onClick={() => setShowClaimModal(false)}>×</button>
                        </div>

                        <div className="modal-body">
                            <div className="voucher-summary">
                                <p><strong>Voucher:</strong> {selectedVoucher.voucher_code}</p>
                                <p><strong>Available Balance:</strong> R {selectedVoucher.current_balance}</p>
                            </div>

                            <div className="form-group">
                                <label>Amount to Claim</label>
                                <input
                                    type="number"
                                    min="1"
                                    max={selectedVoucher.current_balance}
                                    value={claimAmount}
                                    onChange={(e) => setClaimAmount(parseInt(e.target.value) || 0)}
                                />
                                <small>Max: R {selectedVoucher.current_balance}</small>
                            </div>

                            <div className="form-group">
                                <label>Claim Method</label>
                                <select 
                                    value={claimMethod}
                                    onChange={(e) => setClaimMethod(e.target.value)}
                                >
                                    <option value="bank">Bank Transfer</option>
                                    <option value="cash">Cash at Partner Shop</option>
                                    <option value="mobile">Mobile Money</option>
                                </select>
                            </div>

                            {claimMethod === 'bank' && (
                                <div className="bank-details">
                                    <p>Bank details will be collected at the partner shop</p>
                                </div>
                            )}

                            {claimMethod === 'cash' && (
                                <div className="partner-shops">
                                    <h4>Nearby Partner Shops:</h4>
                                    <div className="shop-list">
                                        <div className="shop-item">
                                            <span>Mama Nandi Spaza</span>
                                            <span>📍 Orlando West</span>
                                        </div>
                                        <div className="shop-item">
                                            <span>Bheki Hardware</span>
                                            <span>📍 Diepkloof</span>
                                        </div>
                                    </div>
                                </div>
                            )}

                            <div className="claim-fee">
                                <p>Processing fee: <strong>R10</strong></p>
                                <p>You will receive: <strong>R{claimAmount - 10}</strong></p>
                            </div>

                            <div className="modal-actions">
                                <button 
                                    className="btn-cancel"
                                    onClick={() => setShowClaimModal(false)}
                                >
                                    Cancel
                                </button>
                                <button 
                                    className="btn-confirm-claim"
                                    onClick={handleProcessClaim}
                                >
                                    ✅ Confirm Claim
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default WorkerDashboard;
